from task0 import Grid, GemCell, Color


class ClearingManager:
    def __init__(self, grid: Grid):
        self.grid = grid
        self.score = 0

    def clear_lines(self) -> int:
        """Clears complete lines and returns the number of lines cleared."""
        lines_cleared = 0
        rows_to_clear = []
        for y in range(self.grid.height):
            if all(self.grid.get_cell(x, y) is not None for x in range(self.grid.width)):
                rows_to_clear.append(y)
                lines_cleared += 1

        if lines_cleared > 0:
            self.remove_lines(rows_to_clear)
        return lines_cleared

    def remove_lines(self, rows_to_clear: List[int]) -> None:
        """Removes the specified lines from the grid and shifts the above lines down."""
        for row in rows_to_clear:
            for x in range(self.grid.width):
                self.grid.set_cell(x, row, None)

        for row in rows_to_clear:
            for y in range(row - 1, -1, -1):
                for x in range(self.grid.width):
                    self.grid.set_cell(x, y + 1, self.grid.get_cell(x, y))
                    self.grid.set_cell(x, y, None)

    def find_matches(self) -> List[Tuple[int, int]]:
        """Finds all match-3 or more gems in the grid and returns a list of their coordinates."""
        matches: List[Tuple[int, int]] = []
        # Horizontal matches
        for y in range(self.grid.height):
            for x in range(self.grid.width - 2):
                gem1 = self.grid.get_cell(x, y)
                gem2 = self.grid.get_cell(x + 1, y)
                gem3 = self.grid.get_cell(x + 2, y)

                if gem1 and gem2 and gem3 and gem1.color == gem2.color == gem3.color:
                    match = [(x, y), (x + 1, y), (x + 2, y)]
                    i = x + 3
                    while i < self.grid.width and self.grid.get_cell(i, y) and self.grid.get_cell(i, y).color == gem1.color:
                        match.append((i, y))
                        i += 1
                    matches.extend(match)

        # Vertical matches
        for x in range(self.grid.width):
            for y in range(self.grid.height - 2):
                gem1 = self.grid.get_cell(x, y)
                gem2 = self.grid.get_cell(x, y + 1)
                gem3 = self.grid.get_cell(x, y + 2)
                if gem1 and gem2 and gem3 and gem1.color == gem2.color == gem3.color:
                    match = [(x, y), (x, y + 1), (x, y + 2)]
                    i = y + 3
                    while i < self.grid.height and self.grid.get_cell(x, i) and self.grid.get_cell(x, i).color == gem1.color:
                        match.append((x, i))
                        i += 1
                    matches.extend(match)

        # Remove duplicate coordinates using a set
        return list(set(matches))

    def clear_matches(self) -> int:
        """Clears all matched gems from the grid and returns the number of gems cleared."""
        matches = self.find_matches()
        cleared_count = len(matches)

        for x, y in matches:
            self.grid.set_cell(x, y, None)

        self.drop_floating_gems()
        return cleared_count

    def drop_floating_gems(self) -> None:
        """Moves floating gems down to fill empty spaces."""
        for x in range(self.grid.width):
            empty_pos = -1
            for y in range(self.grid.height):
                if self.grid.get_cell(x, y) is None:
                    if empty_pos == -1:
                        empty_pos = y
                else:
                    if empty_pos != -1:
                        self.grid.set_cell(x, empty_pos, self.grid.get_cell(x, y))
                        self.grid.set_cell(x, y, None)
                        empty_pos += 1

    def resolve_chains(self) -> int:
        """Resolves chain reactions until no more matches are found.  Returns total score earned."""
        total_score = 0
        cleared_this_round = True  # Set to True to start the loop
        while cleared_this_round:
            cleared_count = self.clear_matches()
            if cleared_count > 0:
                score = cleared_count * 10  # Base score, can be adjusted
                total_score += score
                self.score += score  # Update the total score

                # Clear lines after clearing matches, to allow combo.
                lines_cleared = self.clear_lines()
                if lines_cleared > 0:
                    line_score = lines_cleared * lines_cleared * 100 # Tetris scoring
                    total_score += line_score
                    self.score += line_score
            else:
                cleared_this_round = False
        return total_score
